var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"......알겠어. 내가 잘 설득해 볼게.","JPN":"……わかったよ。俺が説得してみる。","ENG":"... I see. I'll talk him through it.","TWN":"……知道了，我會去說服看看的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"아냐. 최선을 다했잖아. 수고했어, 친구.","JPN":"いや、最善は尽くしたぞ。ご苦労さん。","ENG":"It's okay. You tried your best. Thanks, buddy.","TWN":"不，你已經盡力了。辛苦了，朋友。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"어떻습니까? 고칠 수 있는 거죠?","JPN":"どうですか？　直せますね？","ENG":"Well? Can we fix it?","TWN":"怎麼樣？可以修好吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"정비사로 일했던 친구들이 좀 살펴 봤는데...... 역시 힘들겠답니다.","JPN":"整備士として働いていた隊員が調べてみましたが……やはり厳しいみたいです。","ENG":"Some of the guys who were grease monkeys back in the day took a look... and it seems unlikely.","TWN":"做過維修工的朋友檢查過了……還是不行。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"다시 항행하려면 현실세계로 돌아가서 전문 정비사들한테 맡겨야 한다네요.","JPN":"再び航行するには、現実世界に戻り専門の整備士に任せるしかないようです。","ENG":"They say we'll have to surface and get an expert repair crew if we want to make her sail again.","TWN":"如果想重新航行，就要回到現世找維修專家才行。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그, 그럴 리가요. 분명 대여해 준 곳에서 구형 모델이라 수리하기 쉽다고 했는데......","JPN":"そ、そんなはずがありません。貸してくれた業者から、旧型モデルだから修理しやすいと確かに聞いたのに……","ENG":"Th-that can't be right. The rental service said it's easy to repair because it's an older model...","TWN":"怎、怎麼可能。租船給我的人明明說這是舊款型號，所以會很好修理的……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"그건 예비 부품이 있을 때 얘기죠.","JPN":"それは予備の部品がある場合の話です。","ENG":"Sure. When you've got plenty of spare parts.","TWN":"那是在有備用零件的情況。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"파손된 걸 즉석에서 고쳐다 쓰는 건 참전 경험 있는 정비사들이나 해 봤을 걸요.","JPN":"破損した物を即座に修理して使うのは、参戦経験のあるベテラン整備士に限った話ですよ。","ENG":"I doubt anyone can repair these things on the spot, unless they served in the war or something.","TWN":"只有那些有參戰經驗的維修工才能將破損的零件當場修復並使用。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"안 돼......","JPN":"そんな……","ENG":"No...","TWN":"不行……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"이래서는, 이래서는 얘기가 다르잖아......","JPN":"これでは、これでは話が違う……","ENG":"This wasn't what I had in mind...","TWN":"這樣下去，這樣下去不行啊……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"잠깐! 아직 방법이 남아 있습니다!","JPN":"そうだ！　まだ方法はあります！","ENG":"Oh, wait! There's still one more way!","TWN":"等等！還有辦法！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"지금 바로 목적지까지 걸어 가죠!","JPN":"今すぐ目的地まで歩いて行きましょう！","ENG":"We can walk to our destination!","TWN":"現在立刻走到目的地！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"차량 한 대 없이 맨몸으로 이면세계를 횡단하자고?","JPN":"車1台すら無いのに、生身で裏世界を横断するって？","ENG":"You want to traverse the Counterside on foot?","TWN":"你是說隻身橫穿異界？在沒有任何其他移動設備的幫助情形下？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"포식하러 몰려들 침식체들이야 그렇다 쳐도, 이터니움 실드가 버티지 못할 걸.","JPN":"捕食しようと押し寄せてくる侵食体は何とかなるとしても、エタニウムシールドが持たないだろう。","ENG":"The Eternium Shields won't last, not to mention the swarms of C.O.s who want us for lunch.","TWN":"那些前來捕食的侵蝕體就先不說，永恆之金護盾肯定承受不住。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"여기서 포기할 수는 없어요!","JPN":"ここで諦めるわけにはいきません！","ENG":"But I've come too far to give up!","TWN":"我不能就這樣放棄！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그렇게나 찾아 헤맸던 꿈이 저 앞에 있는데......! 어떻게 포기하란 말입니까!","JPN":"あれほど探し求めていた夢が目の前にあるのに……！　それを諦めろと言うんですか！","ENG":"My lifelong dream is sitting right there... I couldn't possibly give up now!","TWN":"我追尋的夢想眼看就要實現了……！叫我如何放棄！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"출발합시다! 어서! 더 늦었다간 들어갈 기회를 놓칠 겁니다!","JPN":"出発しましょう！　はやく！　これ以上遅れてしまうと機会を逃してしまいます！","ENG":"Let's get going! Hurry! We'll miss our window if we delay any further!","TWN":"出發！快！再晚的話就錯過進去的機會了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 녀석들 차림새를 봐, 윌버.","JPN":"こいつらの格好を見ろ、ウィルバー。","ENG":"Look at what these guys are wearing, Wilbur.","TWN":"你看看這些傢伙的穿著，韋爾伯。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하다못해 스틸레인제 방호복도 안 입었어. 소형 이터니움 실드만으론 함선 밖에서 오래 못 버텨.","JPN":"スチールレイン製の防護服すら着ていない。小型エタニウムシールドだけじゃ、艦船の外では長く耐えられない。","ENG":"They're not even wearing Steel Lane protection suits. They won't last long outside the ship with these small Eternium Shields.","TWN":"連防護服都沒有。只靠小型能晶護盾，在艦船外面是撐不了多長時間的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뭐...... 저기 갑옷 입은 녀석은 어떨지 모르겠지만. 한 명으로는 어림도 없지.","JPN":"まあ……あそこにいる鎧の奴はわからないが。どちらにしろ一人じゃ無理だ。","ENG":"Although... Maybe that armored one over there might have a shot... but a single mercenary won't do you much good.","TWN":"嗯……不知道那個穿盔甲的傢伙能不能，但僅憑他一個人根本不可能。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"모르스라면 없는 셈 치는 게 나아.","JPN":"モールスならいないものと思ったほうがいい。","ENG":"Mors hardly even counts as one mercenary.","TWN":"那個莫爾斯，還是不要對他寄有什麼期望。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"저 녀석, 우리가 갑판에서 싸우는 동안 손가락 하나 까딱 안 하고 선실에 있었다고.","JPN":"あいつ、俺たちが甲板で戦っている間すら、指一本動かさずに船室にいたんだから。","ENG":"That jerk didn't even lift a finger and sat in the cabin while we were busting our ass out there.","TWN":"我們在甲板上戰鬥的時候，他的手指連動都沒動一下，就只是一直待在船艙裡。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"아니야......","JPN":"違う……","ENG":"No...","TWN":"不……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"아니야! 이럴 수는 없어!!","JPN":"違う！　こんなはずじゃない！！","ENG":"No! It can't be!","TWN":"不！不可以！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"내가 어떻게 여기까지 왔는데!! 그동안의 고생들이 전부 헛수고라고?!","JPN":"散々な思いをしながらやっとここまで来たのに！　これまでの苦労が全部水の泡になるだと！？","ENG":"After all I've been through to get here... now you're telling me it was all in vain?","TWN":"我費盡千辛萬苦來到這裡！！現在要讓我做的一切都付諸東流嗎？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"크흑, 흑, 으흐윽......!","JPN":"くっ、うぅ、ううっ……！","ENG":"Oh, God, no... *Sob*","TWN":"咳呃，嗚嗚，嗚嗚嗚……！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니, 저희 이대로 돌아가는 거예요?","JPN":"リタお姉ちゃん、私たちこのまま帰るんですか？","ENG":"So are we going back just like that, Rita?","TWN":"麗塔姐姐，我們真的就這樣回去了嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 올 때처럼 빈털터리 신세로 말이지.","JPN":"そうだな。行きも帰りも一文無しで。","ENG":"Yup. Totally empty-handed.","TWN":"嗯，就像來時一樣，兩手空空。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"여기까지 왔는데 조금만 더 도와 주면 안 될까요? 언니한테는 간단한 일이잖아요.","JPN":"ここまで来たんだから、もう少し手伝ってあげるのはダメですか？　リタお姉ちゃんには簡単なことでしょう？","ENG":"But couldn't we help him just a little more while we're here? It should be easy enough for you.","TWN":"都到這裡了，不能再幫幫他嗎？對姐姐來說不過是舉手之勞啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뭘 도와 줘? 저 녀석의 망상을 깨 달라고?","JPN":"手伝う？　妄想からあいつの目を覚ましてやることか？","ENG":"Help him with what? Opening his eyes to reality?","TWN":"幫什麼？讓我幫他打碎夢想？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"여기까지 오게 해 준 것만으로도 난 충분히 도와 줬어.","JPN":"ここまで来させてやっただけでも十分だろ。","ENG":"I already helped him plenty by letting him come this far.","TWN":"跟他一起來這裡，我已經仁至義盡了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"변덕 삼아 유적이니 뭐니 찾으러 왔지만...... 저 꼴을 보니 결국 헛수고였군.","JPN":"気まぐれで遺跡だか何だかを探しに来たものの……全て無駄だったな。","ENG":"I may have agreed to come find those ruins on a whim... but seeing that loser now makes me realize it was a wasted effort.","TWN":"他鬼迷心竅非要來找什麼遺跡……看他現在那個樣子，看來是白忙一場了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하지만 저 녀석에겐 잘된 걸지도 모르지.","JPN":"しかし、あいつにとってはいいことかもしれない。","ENG":"If anything, this might be a good thing for him.","TWN":"但對他來說或許是好事。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네? 이대로 돌아가야 하는데요?","JPN":"え？　このまま帰るしかないのにですか？","ENG":"Huh? But he's got to go back empty-handed.","TWN":"嗯？無功而返還算好事？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"난 저 녀석이 하는 말을 믿지 않아.","JPN":"私はあいつの言葉を信じない。","ENG":"I don't buy his gibberish.","TWN":"我不相信那傢伙說的話。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하지만 유적에 대한 저 녀석의 집착만큼은 진짜야.","JPN":"だが、遺跡に対するあいつの執着だけは本物だ。","ENG":"But his obsession with the ruins is very real.","TWN":"但那傢伙對遺跡的執著是真的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아마 그동안 자기가 헛짓거리를 했다는 사실을 깨달으면 자살해 버릴걸.","JPN":"おそらくこれまで自分が無駄なことをしていたと気付いたら、みずから命を絶つほどのダメージを受けるだろう。","ENG":"If he realizes that he's been chasing after nothing, he'll probably commit suicide.","TWN":"若他意識到自己這段時間都是無用功的話，可能會自殺吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그러니 헛된 희망이라도 부여 잡고 사는 게 저 얼간이한테는 더 나아.","JPN":"だから、無駄な希望だろうが握りしめて生きていけるんだったらまだマシだ。","ENG":"So that fool's better off hanging onto his false hope.","TWN":"所以，對那個傻子來說，哪怕是徒勞的希望也是好的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그치만 평생을 건 꿈을 눈앞에서 포기해야 하다니...... 불쌍해요.","JPN":"でも一生の夢を目の前にして諦めるしかないなんて……可哀想です。","ENG":"But still, he has to give up on his lifelong dream... when it's just within reach. I feel so bad for him.","TWN":"但是一生追求的夢想要在眼前放棄……也太可憐了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이, 넌 사람을 너무 쉽게 믿어서 탈이야.","JPN":"ガキ、お前の問題は人を簡単に信じてしまうことだ。","ENG":"Kid, you believe in people too easily for your own good.","TWN":"小鬼，你太容易相信別人了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네? 그게 왜요?","JPN":"え？　なぜですか？","ENG":"Sorry? What's wrong with that?","TWN":"嗯？怎麼說？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"세상엔 양가죽을 쓰고 다니는 늑대가 너무 많거든.","JPN":"世の中には羊の皮を被った狼が多すぎる。","ENG":"There are too many wolves in sheep's clothing in the world.","TWN":"世上有太多披著羊皮的狼。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"물론 나도 예외는 아니지.","JPN":"もちろん私も例外ではない。","ENG":"Myself included.","TWN":"當然我也不例外。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"헤헤, 거짓말. 언니는 믿을 수 있는 사람이잖아요.","JPN":"へへ、嘘だあ。リタお姉ちゃんは世界一信用できる人ですよ？","ENG":"Hah hah, yeah right. I know I can count on you.","TWN":"嘿嘿，騙人。姐姐是個值得信賴的人。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"젠장. 어쩌다 이런 귀찮은 꼬맹이를 데려 왔는지......","JPN":"まいったな。なぜこんな面倒くさいガキを世話するはめになったんだ……","ENG":"Dammit. I knew I should never have brought this kid along...","TWN":"可惡，怎麼把這麼麻煩的小屁孩帶來了呢……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌, 잠깐 거들어 줘. 함선을 수리해야겠어.","JPN":"ホライズン、ちょっと手を貸せ。艦船を修理する。","ENG":"Give me a hand, Horizon. We're going to repair the ship.","TWN":"地平線，幫我一下，要修理艦船了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"웬일입니까. 방금 전까지 아무런 의욕도 없었으면서.","JPN":"どういう風の吹き回しですか。さっきまではやる気がまったくなかったのに。","ENG":"Well, that's a surprise. You seemed completely unmotivated till just now.","TWN":"怎麼回事？剛剛不是還事不關己的樣子呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"여기까지 온 이상 이터니움 부스러기라도 챙겨서 가야지.","JPN":"ここまで来た以上、エタニウムのカスでも持って帰らないと。","ENG":"We might as well as get a few scraps of Eternium while we're down here.","TWN":"既然都來了，好歹也要帶點永恆之金碎片回去吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그리고 추진부가 맛이 간 함선을 현실세계로 부상시켰다간 도시 한복판에서 추락할지도 몰라.","JPN":"あと推進機がぶっ壊れた艦船を現実世界に浮上させたら、都市のど真ん中に墜落するかもしれない。","ENG":"Besides, surface that ship with its thrusters offline and it could crash right in the middle of downtown.","TWN":"還有，如果把推進器故障的艦船弄回現實世界，可能會在市中心墜落。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"제 사고회로의 분석에 따르면 대시의 응석에 넘어간 것 같습니다만.","JPN":"私の思考回路の分析によると、ただダッシュの甘えに負けただけのようですが。","ENG":"My deduction algorithm suggests that you have fallen for Dash's pestering.","TWN":"根據我的思維分析，你應該是被黛西的撒嬌給影響了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"CPU가 고장났나 보군. 돌아가면 수리부터 받아.","JPN":"CPUが壊れたようだな。帰ったら修理してもらえ。","ENG":"It must be a bug. You should really get yourself checked out when we get back.","TWN":"看來你的CPU出現故障了，回去修理修理吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"이럴 수는 없어...... 이럴 수는 없는 거야......","JPN":"こんなはずじゃない……あり得ないんだ……","ENG":"This can't be... This can't be true...","TWN":"不可能……不可能的……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"자, 선생님. 어서 일어나시죠.","JPN":"さあ、先生。立ち上がってください。","ENG":"Come on, Doc. Please get up.","TWN":"好了，先生。快起來吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"계속 여기서 이러고 있어 봤자 몸만 나빠집니다.","JPN":"ずっとここにいても、具合が悪くなるだけです。","ENG":"Sitting out here will only harm you more.","TWN":"你這樣只會傷了你的身體。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"윌버 씨! 대장님! 저기 보세요!","JPN":"ウィルバーさん！　隊長！　あちらを見てください！","ENG":"Mr. Wilbur! Captain! Look!","TWN":"韋爾伯！隊長！看那邊！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"꼬마야, 이미 끝난 일이야. 괜히 자극하지 말고......","JPN":"お嬢ちゃん、もう終わったことだ。余計なことはやめ……","ENG":"It's over, kid. Don't get him started again...","TWN":"小傢伙，已經結束了。別刺激他……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PMC_NPC_TYPEB_NULL","text":{"KOREA":"어? 고쳐지고 있잖아?","JPN":"え？　直ってる？","ENG":"Huh? The ship's getting fixed?","TWN":"嗯？能修理？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"방금...... 뭐라고......?","JPN":"今……なんと……？","ENG":"What... did you just say?","TWN":"你剛剛……說什麼……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"고쳐졌어......?! 어떻게!","JPN":"直った……！？　どうやって？","ENG":"It's fixed? But how?","TWN":"修好了……？怎麼可能！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_NPC_TYPEB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"리타 언니가 도와 줬어요. 언니는 금속이나 암석들을 마음대로 다룰 수 있거든요.","JPN":"リタお姉ちゃんがやってくれたんです。リタお姉ちゃんは金属や岩石を自由に扱うことができるんですよ。","ENG":"Rita helped out. She can do whatever she wants with metals and rocks and stuff.","TWN":"是麗塔姐姐幫的忙。姐姐能隨心所欲控制金屬和岩石哦。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"그 여자한테...... 저런 힘이 있었다고요?","JPN":"あの女に……そんな力があったと？","ENG":"She... is capable of such a thing?","TWN":"那女人……有那樣的力量？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"왜, 왜 하필 그런 속물한테......?","JPN":"な、なぜよりにもよってあんな俗物に……？","ENG":"But that's so unfair... a materialistic jerk like that having such powers...","TWN":"為、為什麼偏偏是那樣的傢伙有那種力量……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"조치는 대충 끝났어. 함교에 있는 녀석들한테 시동 걸라고 해 봐.","JPN":"措置はあらかた終わった。艦橋にいる奴らにエンジンをかけろと伝えろ。","ENG":"It should be good to go, more or less. Tell the guys on the bridge to try starting the engine.","TWN":"差不多修好了。讓在艦橋的傢伙啟動看看吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"점화됐어! 추진기에 불이 붙었다고!!","JPN":"点火した！　推進機がついたんだ！！","ENG":"We have ignition! The thrusters are back online!","TWN":"點著了！推進器可以點著火了！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"임시 변통이었는데 통했군. 조심히 몰면 이번 탐사까지는 버텨 줄 거다.","JPN":"その場しのぎだったがちゃんと効いたな。慎重に動かせば、今回の探査の間は持ちこたえてくれるだろう｡","ENG":"Huh, so that really worked. It should hold together for the rest of the expedition if you drive it carefully.","TWN":"沒想到臨時措施還算管用。小心駕駛的話可以撐到這次探索結束。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"정말 감사합니다! 사람 일은 어떻게 될지 모른다더니! 하하하하!","JPN":"本当にありがとうございます！　一寸先は闇という言葉を思い出しました！　ハハハハ！","ENG":"Thank you so much! I guess there really is a way, where there is a will! Hah hah hah!","TWN":"真的太感謝了！真是天無絕人之路！哈哈哈哈哈！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"약속하겠습니다! 교과서에 이름이 실리면 당신 얘기는 꼭 넣어 달라고 할게요!","JPN":"約束します！　もし僕の名前が教科書に載る時は、あなたの話もぜひ入れてほしいと頼んでみます！","ENG":"I give you my word! If they ever write about me in textbooks, I'll make sure they include you too!","TWN":"我保證！如果教材上登載我的名字，我一定要求把你的事蹟放上去！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"마음만 받지. 어서 배에 타기나 해.","JPN":"気持ちだけでいい。ほら、さっさと艦船に乗れ。","ENG":"No thanks. Just get on the ship already.","TWN":"心領了，快上船吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"돌아가지 않을 작정인가.","JPN":"戻らないつもりか。","ENG":"So we aren't returning just yet?","TWN":"難道不回去了嗎。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그렇게 됐어. 구경꾼 양반.","JPN":"そういうことになったよ、傍観者さん。","ENG":"I'm afraid so. Enjoying the show thus far?","TWN":"是的，旁觀者先生。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"다른 녀석들이 싸울 때 선실에 얌전히 있었다지?","JPN":"他の奴らが戦っている間、船室でおとなしくしていたんだって？","ENG":"I heard you didn't do jack while everyone else was fighting.","TWN":"聽說其他人打架的時候，你就窩在船艙裡？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 으리으리한 갑옷은 뭐 하러 입고 다니나 모르겠군.","JPN":"そのゴテゴテの鎧はお飾りか？","ENG":"What's all that fancy armor for anyway?","TWN":"真不知道你穿這麼金碧輝煌的盔甲是幹什麼用的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"가엾은 자여. 결정을 뒤집기는 쉬우나 후회를 막기는 어렵도다.","JPN":"哀れな者よ。決定を覆すことは簡単だが、後悔を防ぐことは難しい。","ENG":"Oh, ye woeful fool... Decisions may be easy to overturn, but regret remains forever.","TWN":"可憐的人啊，已決定的容易推翻，但後悔卻難以阻止。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......뭐?","JPN":"……は？","ENG":"What?","TWN":"……什麼？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"고행 끝에 기다리는 것이 눈부신 보상이란 법은 없다. 재물도 경우에 따라선 독이 되거늘.","JPN":"苦行の末に待つものが輝かしい報酬とは限らない。財も時として毒となるもの。","ENG":"Sweet treasure does not always lie at the end of a treacherous journey. And even treasure may at times prove to be poison instead.","TWN":"苦盡不一定會甘來，財寶可能會招來禍端。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"지금이라도 뱃머리를 돌리게 하여라. 역병에 사로잡히기 전에.","JPN":"今からでも針路を変えろ。疫病に襲われる前に。","ENG":"It's not too late to turn the ship around. Make haste, lest the plague fall upon you.","TWN":"建議現在調轉船頭吧，在被瘟疫吞噬之前。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"역병......?","JPN":"疫病……？","ENG":"The plague?","TWN":"瘟疫……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"아, 모르스 씨!","JPN":"あっ、モールスさん！","ENG":"Oh, Ms. Mors!","TWN":"啊，莫爾斯！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"안 다치셨네요! 무사하셔서 다행이에요!","JPN":"怪我はないみたいですね！　無事でよかったです！","ENG":"You're alright! Thank goodness!","TWN":"您沒受傷啊！真是太好了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이 너, 이 녀석과 아는 사이야?","JPN":"お前、こいつのこと知っているのか？","ENG":"You know her, kid?","TWN":"小鬼，你，認識這傢伙？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"넹! 모르스 씨가 준 약 덕분에 멀미가 말끔하게 나았어요!","JPN":"はいっ！　モールスさんからもらった酔い止めのおかげで、すっかり元気になりました！","ENG":"Yup! That pill she gave me drove away my motion sickness!","TWN":"嗯！多虧了莫爾斯給的藥，我不再暈船了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그런데 언니, 손에 그 물수건은 뭐예요? 아까부터 계속 들고 있던데요?","JPN":"ところでリタお姉ちゃん、そのタオルは何ですか？　さっきからずっと持っていましたね？","ENG":"What's that wet towel in your hand for, by the way? You keep carrying it around.","TWN":"但是，姐姐，你手裡的那個濕毛巾是什麼呀？從剛才你就一直拿著。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......됐으니까 얼른 타기나 해.","JPN":"……いいからはやく乗れ。","ENG":"... It's nothing. Just hop on already.","TWN":"……算了，趕快上去。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"충고 하나 하지, 구경꾼 양반.","JPN":"一つ忠告させてもらう、傍観者さん。","ENG":"Let me give you some advice, spectator.","TWN":"我給你一個忠告，旁觀者。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그런 재수없는 소리는 사람 골라 가면서 해. 우리 애가 빚을 졌으니 이번에는 넘어가 주지.","JPN":"そんな縁起でもない話は相手を選んで言え。うちの奴が世話になったみたいだから、今回は聞かなかったことにしてやる。","ENG":"Save your mumbo-jumbo for fools who might actually fall for that crap. I'll let it slide this time since you've been good to the kid.","TWN":"那種垃圾話，最好看準人再說。要不是那小鬼欠你人情，這次就算了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"역병의 악취가...... 짙어지는구나.","JPN":"疫病の悪臭が……濃くなっている。","ENG":"The foul stench of the plague... It grows ever thicker.","TWN":"瘟疫的惡臭……越來越濃了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};